INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", 0.0, "クローチェ", "2023/06/30 12:00:00", 126401, 1, 1, -470.0, 1.47, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 2002, 10001, 1, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", 0.0, "クローチェ", "2023/06/30 12:00:00", 126401, 2, 1, -470.0, 2.15, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 2002, 10002, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", 0.0, "ライラエル", "2023/06/30 12:00:00", 126501, 1, 1, -470.0, 0.0, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 2002, 10003, 2, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", 0.0, "ライラエル", "2023/06/30 12:00:00", 126501, 2, 1, -470.0, 0.0, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 2002, 10004, 1, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", 0.0, "リンド", "2023/09/15 15:00:00", 127702, 1, 2, -470.0, 0.0, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 2002, 10005, 2, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", 0.0, "リンド", "2023/09/15 15:00:00", 127702, 2, 2, -470.0, 0.0, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 2002, 10006, 2, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", 0.0, "ヴルム", "2023/09/15 15:00:00", 127802, 1, 2, -470.0, 0.0, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 2002, 10007, 1, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", 0.0, "ヴルム", "2023/09/15 15:00:00", 127802, 2, 2, -470.0, 6.5, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 2002, 10008, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", 0.0, "アネモネ", "2023/12/15 15:00:00", 129602, 1, 3, -470.0, 0.0, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 2002, 10009, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", 0.0, "アネモネ", "2023/12/15 15:00:00", 129602, 2, 3, -470.0, 0.0, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 2002, 10010, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", 0.0, "ネフィ=ネラ", "2023/12/15 15:00:00", 129701, 1, 3, -470.0, 0.0, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 2002, 10011, 1, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", 0.0, "ネフィ=ネラ", "2023/12/15 15:00:00", 129701, 2, 3, -470.0, 6.2, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 2002, 10012, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", 0.0, "カノン", "2024/03/15 15:00:00", 130301, 1, 4, -470.0, 3.1, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 2002, 10013, 3, 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", 0.0, "カノン", "2024/03/15 15:00:00", 130301, 2, 4, -470.0, 6.15, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 2002, 10014, 3, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", 0.0, "ナーナ", "2024/03/15 15:00:00", 130401, 1, 4, -470.0, 0.0, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 2002, 10015, 2, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", 0.0, "ナーナ", "2024/03/15 15:00:00", 130401, 2, 4, -470.0, 3.35, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 2002, 10016, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 0.0, "ホウオウ", "2024/06/15 15:00:00", 130502, 1, 5, -470.0, 0.0, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 2002, 10017, 1, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 0.0, "ホウオウ", "2024/06/15 15:00:00", 130502, 2, 5, -470.0, 3.18, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 2002, 10018, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 0.0, "ホウオウ", "2024/06/15 15:00:00", 130503, 3, 5, -470.0, 0.0, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 2002, 10019, 4, 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 0.0, "ネア", "2024/06/15 15:00:00", 123301, 1, 5, -470.0, 4.9, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 2002, 10020, 1, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 0.0, "ネア", "2024/06/15 15:00:00", 123301, 2, 5, -470.0, 4.8, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 2002, 10021, 1, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", 0.0, "カリザ", "2024/09/15 15:00:00", 133301, 1, 6, -470.0, 4.922, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 2002, 10022, 3, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", 0.0, "カリザ", "2024/09/15 15:00:00", 133301, 2, 6, -470.0, 9.638, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 2002, 10023, 3, 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", 0.0, "ミーア", "2024/09/15 15:00:00", 133401, 1, 6, -470.0, 2.88, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 2002, 10024, 1, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", 0.0, "ミーア", "2024/09/15 15:00:00", 133401, 2, 6, -470.0, 4.818, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 2002, 10025, 5, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", 0.0, "グレイス", "2024/12/15 15:00:00", 133002, 1, 7, -470.0, 1.78, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 2002, 10026, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", 0.0, "グレイス", "2024/12/15 15:00:00", 133002, 2, 7, -470.0, 6.15, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 2002, 10027, 1, 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", 0.0, "ヴァイオレット", "2024/12/15 15:00:00", 133102, 1, 7, -470.0, 4.28, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 2002, 10028, 6, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", 0.0, "ヴァイオレット", "2024/12/15 15:00:00", 133102, 2, 7, -470.0, 0.0, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 2002, 10029, 1, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", 0.0, "ルルィ", "2025/03/15 15:00:00", 136902, 1, 8, -470.0, 5.53, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 2002, 10030, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", 0.0, "ルルィ", "2025/03/15 15:00:00", 136902, 2, 8, -470.0, 6.05, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 2002, 10031, 9, 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", 0.0, "デュラン", "2025/03/15 15:00:00", 137001, 1, 8, -470.0, 0.0, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 2002, 10032, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", 0.0, "デュラン", "2025/03/15 15:00:00", 137001, 2, 8, -470.0, 0.0, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 2002, 10033, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", 0.0, "サツキ", "2025/06/16 15:00:00", 135902, 1, 9, -470.0, 0.0, "おう\n好きなもん持ってきな", 2002, 10034, 2, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", 0.0, "サツキ", "2025/06/16 15:00:00", 135902, 2, 9, -470.0, 4.935, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 2002, 10035, 1, 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", 0.0, "ユキノ", "2025/06/16 15:00:00", 135802, 1, 9, -470.0, 7.441, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 2002, 10036, 2, 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", 0.0, "ユキノ", "2025/06/16 15:00:00", 135802, 2, 9, -470.0, 0.0, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 2002, 10037, 7, 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", 0.0, "クルル", "2025/09/16 15:00:00", 130901, 1, 10, -470.0, 2.295, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2002, 10038, 2, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", 0.0, "クルル", "2025/09/16 15:00:00", 130901, 2, 10, -470.0, 6.281, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 2002, 10039, 1, 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", 0.0, "ヴォルガーノ", "2025/09/16 15:00:00", 137701, 1, 10, -470.0, 5.549, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 2002, 10040, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", 0.0, "ヴォルガーノ", "2025/09/16 15:00:00", 137701, 2, 10, -470.0, 2.64, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 2002, 10041, 3, 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", 0.0, "ライラエル", "2025/12/15 15:00:00", 132801, 1, 11, -470.0, 7.642, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 2002, 10042, 7, 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", 0.0, "ライラエル", "2025/12/15 15:00:00", 132802, 2, 11, -470.0, 0.0, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 2002, 10043, 1, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", 0.0, "クローチェ", "2025/12/15 15:00:00", 134502, 1, 11, -470.0, 0.0, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 2002, 10044, 1, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", 0.0, "クローチェ", "2025/12/15 15:00:00", 134501, 2, 11, -470.0, 3.72, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 2002, 10045, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", 0.0, "ネフィ＝ネラ", "2026/03/16 12:00:00", 138201, 1, 12, -470.0, 4.991, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 2002, 10046, 2, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", 0.0, "ネフィ＝ネラ", "2026/03/16 12:00:00", 138201, 2, 12, -470.0, 3.877, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 2002, 10047, 1, 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", 0.0, "アラクネ", "2026/03/16 12:00:00", 136001, 1, 12, -470.0, 1.71, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 2002, 10048, 4, 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", 0.0, "アラクネ", "2026/03/16 12:00:00", 136001, 2, 12, -470.0, 5.32, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 2002, 10049, 5, 2);
